import React, { useState } from 'react';
import { StyleSheet, Text, View, Button } from 'react-native';

const OfflineTokenGenerator = () => {
  const [currentToken, setCurrentToken] = useState('');

  const generateNewToken = () => {
    const randomPart = Math.random().toString(36).substring(2);
    const newToken = `offline-${randomPart}`;
    setCurrentToken(newToken);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Offline Session Token Generator</Text>
      <View style={styles.tokenDisplayContainer}>
        <Text style={styles.tokenLabel}>Current Token:</Text>
        <Text style={styles.tokenText}>{currentToken || 'No token generated yet'}</Text>
      </View>
      <Button
        title="Generate New Offline Token"
        onPress={generateNewToken}
      />
    </View>
  );
};

